mapper.update:
UPDATE items
SET favorite_flg = #{favorite}
WHERE id = #{id}
AND user_id = #{userId}

mapper.select:
SELECT items.id, items.name, items.category_id AS categoryId, items.amount, items.deadline, items.purchase_date AS purchaseDate, items.others, items.status, items.favorite_flg AS favorite, categories.name AS categoryName FROM items INNER JOIN categories ON items.category_id = categories.id WHERE items.status <> 0 AND items.user_id = #{userId}
AND items.category_id = #{category}
AND (items.deadline - CURRENT_DATE) <= 3
ORDER BY items.deadline ASC

mapper.delete:
DELETE FROM shopping_list
WHERE id = #{id}
AND user_id = #{userId}
